import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface CartSummary {
  itemCount: number;
  totalPrice: number;
  savings: number;
}

interface Item {
  name: string;
  price: number;
  savings: number;
}

interface ShoppingCartData {
  cartSummary: CartSummary;
  items: Item[];
}

export default function Widget() {
  const shoppingCartData = response.data as ShoppingCartData;
  const { cartSummary, items } = shoppingCartData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: '#F5F5F5',
        borderRadius: 3,
        boxShadow: 'inset 0px 0px 5px rgba(0,0,0,0.1), 4px 4px 10px rgba(0,0,0,0.1)',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              Shopping Cart
            </Typography>
            <Stack direction="row" alignItems="center" spacing={1}>
              <Typography variant="body2" color="text.secondary">
                Total Items:
              </Typography>
              <Chip label={cartSummary.itemCount} size="small" sx={{ fontSize: '12px', bgcolor: '#CDDC39', color: '#FFFFFF' }} />
            </Stack>
            <Stack direction="row" alignItems="center" spacing={1} sx={{ mt: 1 }}>
              <Typography variant="body2" color="text.secondary">
                Total Price:
              </Typography>
              <Typography variant="h6" sx={{ color: '#FF5722', fontWeight: 600 }}>
                ${cartSummary.totalPrice.toFixed(2)}
              </Typography>
            </Stack>
            <Stack direction="row" alignItems="center" spacing={1}>
              <Typography variant="body2" color="text.secondary">
                Savings:
              </Typography>
              <Typography
                variant="body2"
                sx={{ color: cartSummary.savings > 0 ? '#10B981' : '#EF4444', fontWeight: 500 }}
              >
                {cartSummary.savings > 0 ? <TrendingUp fontSize="small" /> : <TrendingDown fontSize="small" />}
                ${cartSummary.savings.toFixed(2)}
              </Typography>
            </Stack>
          </Box>

          <Stack spacing={1}>
            {items.map((item, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" sx={{ mb: 0.5 }}>
                  <Typography variant="body2" sx={{ color: '#333333', fontWeight: 600 }}>
                    {item.name}
                  </Typography>
                  <Stack direction="row" alignItems="center" spacing={0.5}>
                    <Typography variant="body2" sx={{ color: '#666666' }}>
                      ${item.price.toFixed(2)}
                    </Typography>
                    <Chip
                      label={`Save $${item.savings.toFixed(2)}`}
                      size="small"
                      sx={{ fontSize: '10px', bgcolor: '#CDDC39', color: '#FFFFFF' }}
                    />
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
